import * as t from "io-ts";
import { Optional, optionalNumber } from "../../../utils";
import { DotFeeOptions } from "./dotFeeOptions";
import { RecipientEntry } from "./recipientEntry";
import { BaseIntent } from "./baseIntent";

export const DotBaseIntent = t.intersection([
  BaseIntent,
  t.partial({
    senderAddressIndex: optionalNumber,
    fee: Optional(DotFeeOptions),
    recipients: Optional(t.array(RecipientEntry)),
  }),
]);

export type DotBaseIntent = t.TypeOf<typeof DotBaseIntent>;
